from pydantic import BaseModel
from langchain_openai import ChatOpenAI

llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)


class ClaimVerdict(BaseModel):
    claim: str
    supported: bool
    evidence: str


class FaithfulnessResult(BaseModel):
    claims: list[ClaimVerdict]

    @property
    def score(self) -> float:
        if not self.claims:
            return 0.0
        return sum(c.supported for c in self.claims) / len(self.claims)


def check_faithfulness(answer: str, context: str) -> FaithfulnessResult:
    structured = llm.with_structured_output(FaithfulnessResult)
    return structured.invoke(
        f"""Break the answer into atomic claims and verify each one against the context.
A claim is supported only if the context explicitly states or clearly implies it.

Context: {context}

Answer: {answer}"""
    )


result = check_faithfulness(
    answer="Electronics can be returned within 30 days. Extended warranty covers 2 years.",
    context="Electronics: 30-day return window. Original packaging required.",
)
print(f"Faithfulness: {result.score:.2f}")
for claim in result.claims:
    symbol = "✓" if claim.supported else "✗"
    print(f"  {symbol} {claim.claim}")
# ✓ Electronics can be returned within 30 days.
# ✗ Extended warranty covers 2 years.
